<script setup lang="ts">import { AlertTriangle, Inbox, LoaderCircle, RotateCcw } from '@lucide/vue'; defineProps<{ state: 'loading' | 'empty' | 'error'; title?: string; description?: string }>(); defineEmits<{ retry: [] }>();</script>
<template><div class="panel grid min-h-52 place-items-center p-8 text-center"><div><LoaderCircle v-if="state==='loading'" class="mx-auto mb-4 animate-spin text-[var(--brand)]" :size="30"/><AlertTriangle v-else-if="state==='error'" class="mx-auto mb-4 text-[var(--danger)]" :size="30"/><Inbox v-else class="mx-auto mb-4 muted" :size="32"/><h3 class="font-extrabold">{{ title || (state==='loading'?'正在加载':'这里还没有内容') }}</h3><p v-if="description" class="muted mt-2 max-w-lg text-sm">{{ description }}</p><button v-if="state==='error'" class="btn btn-secondary mt-5" type="button" @click="$emit('retry')"><RotateCcw :size="16"/>重试</button></div></div></template>
